      "Support": "Weakly supported"
    },
    "Blastomycosis": {
      "Supporting": "Exposure in endemic regions (New England/SE US), pulmonary nodules, and lymphadenopathy.",
      "Against": "Subacute presentation, lack of cutaneous ulcers or classic lung cavitation, and relatively indolent course.",
      "Support": "Weakly supported"
    },
    "Diffuse large B-cell lymphoma": {
      "Supporting": "B-symptoms (fever, fatigue), lymphadenopathy, and pulmonary nodules.",
      "Against": "Absence of night sweats, weight loss, or constitutional decline; normal white-cell count and differential; normal liver function tests.",
      "Support": "Weakly supported"
    },
    "Paraneoplastic inflammatory polyarthritis": {
      "Supporting": "Joint symptoms with hilar/mediastinal adenopathy and pulmonary nodules.",
      "Against": "Usually associated with specific underlying malignancy, which has not yet been confirmed.",
      "Support": "Weakly supported"
    },
    "Systemic lupus erythematosus": {
      "Supporting": "Arthralgia/arthritis, fatigue, and fever.",
      "Against": "Normal urinalysis (no nephritis), absence of characteristic rashes, cytopenias, or positive serologic markers mentioned.",
      "Support": "Weakly supported"
    }
  },
